mapper.select:
SELECT assignment.id , assignment.deleted , assignment.created_at as createdAt , assignment.modified_at as modifiedAt , assignment.assignment_name as assignmentName , assignment.due_date as dueDate , assignment.is_complete as isComplete , assignment.category
, assignment.subject_id as subjectId , subject.subject_name as subjectName
, CASE WHEN assignment.due_date < CURDATE() THEN 'OVERDUE' WHEN assignment.due_date = CURDATE() THEN 'WITHIN_24_HOURS' WHEN assignment.due_date = DATE_ADD(CURDATE(), INTERVAL 1 DAY) THEN 'WITHIN_48_HOURS' ELSE 'NORMAL' END as deadlineStatus FROM assignment JOIN subject ON assignment.subject_id = subject.id WHERE assignment.id = #{req.id}

mapper.sql:
WHERE assignment.id is not null
AND assignment.deleted = #{req.deleted}
AND subject.subject_name = #{req.subjectName}

