mapper.select:
SELECT assignment.id FROM assignment LEFT JOIN subject ON assignment.subject_id = subject.id LEFT JOIN semester ON subject.semester_id = semester.id
AND semester.user_id = #{reqUserId}
ORDER BY assignment.id DESC
